static inline void afn_bp0_move_1() {
    if (!afn_player_frozen) { afn_input_fwd += 256; if (tm_move_timer == 0) tm_player_facing = 0; }
}
static inline void afn_bp0_19() {
    // unsupported bp action: type 258
}
static inline void afn_bp0_walk_6() {
    if (!afn_speed_prio) afn_move_speed = 100;
}
static inline void afn_bp0_orbit_9() {
    orbit_angle -= 500;
}
static inline void afn_bp0_orbit_13() {
    orbit_angle += 500;
}
static inline void afn_bp0_23() {
    // unsupported bp action: type 258
}
static inline void afn_bp0_26() {
    afn_play_sound(0);
}
static inline void afn_bp0_start() {
    afn_bp0_26();
}
static inline void afn_bp0_key_held() {
  if (key_is_down(KEY_UP)) {
    afn_bp0_move_1();
    afn_bp0_19();
    afn_bp0_walk_6();
  }
  if (key_is_down(KEY_L)) {
    afn_bp0_orbit_9();
  }
  if (key_is_down(KEY_R)) {
    afn_bp0_orbit_13();
  }
}
static inline void afn_bp0_key_pressed() {
}
static inline void afn_bp0_key_released() {
  if (key_released(KEY_UP)) {
    afn_bp0_23();
  }
}
static inline void afn_bp0_update() {
}
static inline void afn_bp0_collision() {
}
static inline void afn_bp0_collision2d() {
}

