static inline void afn_bp_dispatch_collision(void) {
  for (int i = 0; i < 1; i++) {
    if (afn_bp_instances[i].sceneMode != afn_current_mode) continue;
    if (afn_bp_instances[i].sceneMask != 0xFFFFFFFFu && !(afn_bp_instances[i].sceneMask & (1u << tm_scene_idx))) continue;
    if (afn_bp_def_frozen[afn_bp_instances[i].bpIdx]) continue;
    if (afn_bp_instances[i].sprIdx != afn_collided_sprite) continue;
    if (afn_bp_instances[i].sprIdx >= 0 && afn_bp_instances[i].sprIdx < NUM_SPRITES && !afn_sprite_visible[afn_bp_instances[i].sprIdx]) continue;
    afn_bp_cur_spr_idx = afn_bp_instances[i].sprIdx;
    afn_bp_cur_tm_obj = afn_bp_instances[i].tmObjIdx;
    switch (afn_bp_instances[i].bpIdx) {
    case 0: afn_bp0_collision(); break;
    }
  }
}
static inline void afn_bp_dispatch_collision2d(void) {
  for (int i = 0; i < 1; i++) {
    if (afn_bp_instances[i].sceneMode != afn_current_mode) continue;
    if (afn_bp_instances[i].sceneMask != 0xFFFFFFFFu && !(afn_bp_instances[i].sceneMask & (1u << tm_scene_idx))) continue;
    if (afn_bp_def_frozen[afn_bp_instances[i].bpIdx]) continue;
    if (afn_bp_instances[i].tmObjIdx != afn_collided_tm_obj) continue;
    switch (afn_bp_instances[i].bpIdx) {
    case 0: afn_bp0_collision2d(); break;
    }
  }
}

